import React from "react";
import { useNavigate } from "react-router-dom";

function Register() {
    const navigate = useNavigate();

    const handleSubmit = (e) => {
        e.preventDefault();
        // Add validation / API call here
        navigate("/login");
    };

    return (
        <div className="min-h-screen bg-gray-100 flex flex-col items-center">

            {/* Header */}
            <header className="w-full bg-slate-800 text-white py-4 text-center shadow">
                <h2 className="text-xl font-semibold tracking-wide">DocBook</h2>
            </header>

            {/* Card */}
            <div className="bg-white w-[500px] mt-8 p-8 rounded-2xl shadow-lg">
                <h2 className="text-2xl font-bold text-center text-slate-700">Create Account</h2>
                <p className="text-center text-gray-500 mb-6">Join DocBook</p>

                <form onSubmit={handleSubmit}>

                    <div className="flex gap-4">
                        <div className="flex flex-col w-full mb-4">
                            <label className="text-sm font-medium">Full Name</label>
                            <input type="text" placeholder="Enter your name" className="input" required />
                        </div>

                        <div className="flex flex-col w-full mb-4">
                            <label className="text-sm font-medium">Email</label>
                            <input type="email" placeholder="Enter your email" className="input" required />
                        </div>
                    </div>

                    <div className="flex gap-4">
                        <div className="flex flex-col w-full mb-4">
                            <label className="text-sm font-medium">Date of Birth</label>
                            <input type="date" className="input" required />
                        </div>

                        <div className="flex flex-col w-full mb-4">
                            <label className="text-sm font-medium">Gender</label>
                            <select className="input" required>
                                <option value="">Select</option>
                                <option>Male</option>
                                <option>Female</option>
                                <option>Other</option>
                            </select>
                        </div>
                    </div>

                    <div className="flex flex-col mb-4">
                        <label className="text-sm font-medium">Address</label>
                        <textarea placeholder="Enter your address" className="input" required></textarea>
                    </div>

                    <div className="flex flex-col mb-4">
                        <label className="text-sm font-medium">Contact Number</label>
                        <input type="tel" placeholder="Enter phone number" className="input" required />
                    </div>

                    <div className="flex gap-4">
                        <div className="flex flex-col w-full mb-4">
                            <label className="text-sm font-medium">Password</label>
                            <input type="password" placeholder="Enter password" className="input" required />
                        </div>

                        <div className="flex flex-col w-full mb-4">
                            <label className="text-sm font-medium">Confirm Password</label>
                            <input type="password" placeholder="Confirm password" className="input" required />
                        </div>
                    </div>

                    <button className="w-full bg-slate-800 text-white py-3 rounded-lg font-semibold hover:bg-slate-700 transition">
                        Sign Up
                    </button>

                </form>

                <p className="text-center text-sm mt-4">
                    Already have an account? 
                    <span
                        onClick={() => navigate("/login")}
                        className="text-slate-800 font-semibold cursor-pointer ml-1"
                    >
                        Login
                    </span>
                </p>
            </div>

            {/* Tailwind Input Style */}
            <style>
                {`
                .input {
                    padding: 10px;
                    border-radius: 8px;
                    border: 1px solid #d1d5db;
                    margin-top: 5px;
                    outline: none;
                    transition: 0.2s;
                }
                .input:focus {
                    border-color: #334155;
                    box-shadow: 0 0 0 2px rgba(51,65,85,0.2);
                }
                `}
            </style>

        </div>
    );
}

export default Register;
